+/**
+ * Email notification adapter.
+ *
+ * Sends notifications via email. Currently a stub — in production this would
+ * integrate with an SMTP server, SendGrid, AWS SES, or similar service.
+ *
+ * Implements NotificationAdapter so it can be registered with
+ * NotificationService.registerAdapter().
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailConfig {
+  /** Default "from" address for outgoing emails. */
+  fromAddress: string;
+  /** SMTP host (for future production use). */
+  smtpHost?: string;
+  /** SMTP port (for future production use). */
+  smtpPort?: number;
+}
+
+export const defaultEmailConfig: EmailConfig = {
+  fromAddress: 'noreply@taskflowpro.com',
+};
+
+export class EmailAdapter implements NotificationAdapter {
+  readonly channel: NotificationChannel = 'email';
+  private logger = new Logger('EmailAdapter');
+  private sentEmails: NotificationPayload[] = [];
+
+  constructor(private config: EmailConfig = defaultEmailConfig) {}
+
+  /**
+   * Send an email notification.
+   *
+   * Currently logs the email and stores it in memory for testing.
+   * Production implementation would call an email provider API here.
+   */
+  async send(payload: NotificationPayload): Promise<void> {
+    this.logger.info(
+      `Sending email from ${this.config.fromAddress} to ${payload.recipient}: ${payload.subject}`,
+    );
+    this.sentEmails.push(payload);
+  }
+
+  /**
+   * Get all sent emails. Useful for testing.
+   */
+  getSentEmails(): NotificationPayload[] {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Clear sent email history. Useful for testing.
+   */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+}

