parameters.content:
/**
 * Notification model types for the event-driven notification system.
 *
 * Architecture: All notifications flow through the EventBus. When a domain
 * event occurs (e.g., order:created), the NotificationService receives it
 * via EventBus subscription and dispatches to the appropriate
 * NotificationAdapter(s) based on channel.
 *
 * Constraints:
 * - All notification delivery MUST go through a NotificationAdapter.
 * - NotificationChannel is extensible — add new channels by implementing
 *   the NotificationAdapter interface in src/adapters/.
 * - NotificationType categorizes the business purpose of the notification.
 */

/**
 * The delivery channel for a notification.
 * Each channel has a corresponding adapter in src/adapters/.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Business categories for notifications.
 * Used for filtering, preferences, and routing logic.
 */
export type NotificationType =
  | 'order:confirmation'
  | 'order:status-update'
  | 'user:welcome'
  | 'user:profile-updated';

/**
 * Payload passed to a NotificationAdapter for delivery.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  metadata?: Record<string, string>;
}

/**
 * Persisted record of a sent notification.
 */
export interface NotificationRecord {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  sentAt: Date;
  metadata?: Record<string, string>;
}

/**
 * Base interface for all notification adapters.
 *
 * Architecture constraint: Every notification channel (email, webhook, SMS,
 * in-app) MUST have an adapter that implements this interface. The
 * NotificationService dispatches to adapters — it never sends notifications
 * directly.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts
 * 2. Create an adapter class implementing NotificationAdapter in src/adapters/
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. Must be unique per NotificationService. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * @throws Error if delivery fails (the NotificationService logs the failure).
   */
  send(payload: NotificationPayload): Promise<void>;
}

/**
 * Email notification adapter.
 *
 * Sends notifications via email. Currently a stub — in production this would
 * integrate with an SMTP server, SendGrid, AWS SES, or similar service.
 *
 * Implements NotificationAdapter so it can be registered with
 * NotificationService.registerAdapter().
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Default "from" address for outgoing emails. */
  fromAddress: string;
  /** SMTP host (for future production use). */
  smtpHost?: string;
  /** SMTP port (for future production use). */
  smtpPort?: number;
}

export const defaultEmailConfig: EmailConfig = {
  fromAddress: 'noreply@taskflowpro.com',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: NotificationPayload[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Send an email notification.
   *
   * Currently logs the email and stores it in memory for testing.
   * Production implementation would call an email provider API here.
   */
  async send(payload: NotificationPayload): Promise<void> {
    this.logger.info(
      `Sending email from ${this.config.fromAddress} to ${payload.recipient}: ${payload.subject}`,
    );
    this.sentEmails.push(payload);
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

